        start = s;
        end = e;
      } else {
        start = parseInt(rangePart, 10);
        if (isNaN(start)) throw new Error(`Invalid step base: ${rangePart}`);
      }
    }

    if (start < min || end > max) {
      throw new Error(`Value out of range [${min}-${max}]: ${field}`);
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range (start-end)
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${field}`);
    if (start > end) throw new Error(`Range start > end: ${field}`);
    if (start < min || end > max) throw new Error(`Value out of range [${min}-${max}]: ${field}`);
    return generateRange(start, end);
  }

  // Single number
  const value = parseInt(field, 10);
  if (isNaN(value)) throw new Error(`Invalid value: ${field}`);
  if (value < min || value > max) throw new Error(`Value ${value} out of range [${min}-${max}]`);
  return [value];
}

