type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_BOUNDS: Record<keyof CronResult, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

function buildRange(start: number, end: number): number[] {
  const out: number[] = [];
  for (let i = start; i <= end; i++) out.push(i);
  return out;
}

function assertInBounds(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of bounds [${min}, ${max}] in "${context}"`);
  }
}

function parseSingleToken(token: string, min: number, max: number): number[] {
  // Wildcard
  if (token === "*") {
    return buildRange(min, max);
  }

  // Step: */n or base-top/n
  if (token.includes("/")) {
    const slashIdx = token.indexOf("/");
    const stepPart = token.slice(slashIdx + 1);
    const basePart = token.slice(0, slashIdx);
    const step = parseInt(stepPart, 10);

    if (!stepPart || isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step in "${token}"`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (basePart !== "*") {
      if (basePart.includes("-")) {
        const [lo, hi] = basePart.split("-").map(Number);
        if (isNaN(lo) || isNaN(hi) || lo > hi) throw new SyntaxError(`Invalid range in "${token}"`);
        assertInBounds(lo, min, max, token);
        assertInBounds(hi, min, max, token);
        rangeMin = lo;
        rangeMax = hi;
      } else {
        const base = parseInt(basePart, 10);
        if (isNaN(base)) throw new SyntaxError(`Invalid base in "${token}"`);
        assertInBounds(base, min, max, token);
        rangeMin = base;
      }
    }

    const out: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) out.push(i);
    return out;
  }

  // Range: a-b
  if (token.includes("-")) {
    const parts = token.split("-");
    if (parts.length !== 2) throw new SyntaxError(`Invalid range "${token}"`);
    const lo = parseInt(parts[0], 10);
    const hi = parseInt(parts[1], 10);
    if (isNaN(lo) || isNaN(hi)) throw new SyntaxError(`Non-numeric range values in "${token}"`);
    if (lo > hi) throw new RangeError(`Range start exceeds end in "${token}"`);
    assertInBounds(lo, min, max, token);
    assertInBounds(hi, min, max, token);
    return buildRange(lo, hi);
  }

  // Single number
  const num = parseInt(token, 10);
  if (isNaN(num) || String(num) !== token.trim()) {
    throw new SyntaxError(`Invalid cron token "${token}"`);
  }
  assertInBounds(num, min, max, token);
  return [num];
}

function parseField(expr: string, min: number, max: number): number[] {
  if (!expr || !expr.trim()) {
    throw new SyntaxError(`Empty cron field`);
  }

  // Comma-separated list — each item is independently parsed
  if (expr.includes(",")) {
    const tokens = expr.split(",");
    const seen = new Set<number>();
    for (const token of tokens) {
      for (const v of parseSingleToken(token.trim(), min, max)) {
        seen.add(v);
      }
    }
    return [...seen].sort((a, b) => a - b);
  }

  return parseSingleToken(expr.trim(), min, max);
}

