function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  const values = new Set<number>();

  for (const part of field.split(",")) {
    if (part === "*") {
      range(min, max).forEach((v) => values.add(v));
    } else if (part.startsWith("*/")) {
      const step = parseInt(part.slice(2), 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value: ${part}`);
      }
      for (let i = min; i <= max; i += step) {
        values.add(i);
      }
    } else if (part.includes("/")) {
      const [rangePart, stepPart] = part.split("/");
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value: ${part}`);
      }
      let start = min;
      let end = max;
      if (rangePart !== "*") {
        if (rangePart.includes("-")) {
          const [s, e] = rangePart.split("-").map((n) => parseInt(n, 10));
          start = s;
          end = e;
        } else {
          start = parseInt(rangePart, 10);
        }
      }
      if (isNaN(start) || isNaN(end)) {
        throw new Error(`Invalid range: ${part}`);
      }
      validateRange(start, min, max, part);
      validateRange(end, min, max, part);
      for (let i = start; i <= end; i += step) {
        values.add(i);
      }
    } else if (part.includes("-")) {
      const [startStr, endStr] = part.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) {
        throw new Error(`Invalid range: ${part}`);
      }
      if (start > end) {
        throw new Error(`Range start exceeds end: ${part}`);
      }
      validateRange(start, min, max, part);
      validateRange(end, min, max, part);
      range(start, end).forEach((v) => values.add(v));
    } else {
      const num = parseInt(part, 10);
      if (isNaN(num)) {
        throw new Error(`Invalid value: ${part}`);
      }
      validateRange(num, min, max, part);
      values.add(num);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

function validateRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} out of range [${min}, ${max}] in expression: ${context}`
    );
  }
}

