interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronExpression, FieldConfig> = {
  minute:     { min: 0, max: 59 },
  hour:       { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month:      { min: 1, max: 12 },
  dayOfWeek:  { min: 0, max: 6  },
};

function expandRange(from: number, to: number, step = 1): number[] {
  if (step <= 0) throw new Error(`Step must be a positive integer, got ${step}`);
  const result: number[] = [];
  for (let i = from; i <= to; i += step) {
    result.push(i);
  }
  return result;
}

function assertInRange(value: number, config: FieldConfig, context: string): void {
  if (value < config.min || value > config.max) {
    throw new Error(
      `Value ${value} is out of range [${config.min}-${config.max}] in "${context}"`
    );
  }
}

function parseField(field: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Comma-separated list — split first, recurse into each segment
  if (field.includes(',')) {
    const seen = new Set<number>();
    for (const segment of field.split(',')) {
      for (const v of parseField(segment.trim(), config)) {
        seen.add(v);
      }
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  // Step value: */step  |  start/step  |  start-end/step
  if (field.includes('/')) {
    const slashIdx = field.lastIndexOf('/');
    const left = field.slice(0, slashIdx);
    const stepStr = field.slice(slashIdx + 1);
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step "${stepStr}" in expression "${field}"`);
    }

    let from: number;
    let to: number;

    if (left === '*') {
      from = min;
      to = max;
    } else if (left.includes('-')) {
      const [s, e] = left.split('-').map(Number);
      if (isNaN(s) || isNaN(e)) throw new Error(`Invalid range in "${field}"`);
      assertInRange(s, config, field);
      assertInRange(e, config, field);
      if (s > e) throw new Error(`Range start ${s} exceeds end ${e} in "${field}"`);
      from = s;
      to = e;
    } else {
      from = parseInt(left, 10);
      if (isNaN(from)) throw new Error(`Invalid step expression "${field}"`);
      assertInRange(from, config, field);
      to = max;
    }

    return expandRange(from, to, step);
  }

  // Wildcard
  if (field === '*') {
    return expandRange(min, max);
  }

  // Range: n-m
  if (field.includes('-')) {
    const parts = field.split('-');
    if (parts.length !== 2) throw new Error(`Invalid range "${field}"`);
    const start = parseInt(parts[0], 10);
    const end = parseInt(parts[1], 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range "${field}"`);
    assertInRange(start, config, field);
    assertInRange(end, config, field);
    if (start > end) throw new Error(`Range start ${start} exceeds end ${end} in "${field}"`);
    return expandRange(start, end);
  }

  // Single numeric value
  const value = parseInt(field, 10);
  if (isNaN(value) || String(value) !== field.trim()) {
    throw new Error(`Invalid cron field value "${field}"`);
  }
  assertInRange(value, config, field);
  return [value];
}

