type FieldName = keyof CronResult;

const FIELD_RANGES: Record<FieldName, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

function validateBounds(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in expression "${context}"`);
  }
}

function parseField(raw: string, min: number, max: number): number[] {
  const field = raw.trim();

  if (!field) {
    throw new SyntaxError("Empty cron field");
  }

  // Comma-separated list — recurse on each part, deduplicate, sort
  if (field.includes(",")) {
    const parts = field.split(",");
    const merged = new Set<number>();
    for (const part of parts) {
      for (const v of parseField(part, min, max)) {
        merged.add(v);
      }
    }
    return [...merged].sort((a, b) => a - b);
  }

  // Step expression: base/step  (base is *, number, or range)
  if (field.includes("/")) {
    const slashIdx = field.indexOf("/");
    const baseStr = field.slice(0, slashIdx);
    const stepStr = field.slice(slashIdx + 1);
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0 || String(step) !== stepStr.trim()) {
      throw new SyntaxError(`Invalid step value "${stepStr}" in "${field}"`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (baseStr === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (baseStr.includes("-")) {
      const [s, e] = baseStr.split("-").map((x) => parseInt(x, 10));
      if (isNaN(s) || isNaN(e)) {
        throw new SyntaxError(`Invalid range "${baseStr}" in "${field}"`);
      }
      validateBounds(s, min, max, field);
      validateBounds(e, min, max, field);
      if (s > e) {
        throw new RangeError(`Range start ${s} exceeds end ${e} in "${field}"`);
      }
      rangeMin = s;
      rangeMax = e;
    } else {
      const start = parseInt(baseStr, 10);
      if (isNaN(start)) {
        throw new SyntaxError(`Invalid base "${baseStr}" in "${field}"`);
      }
      validateBounds(start, min, max, field);
      rangeMin = start;
      rangeMax = max;
    }

    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (field === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Range: start-end
  if (field.includes("-")) {
    const dashIdx = field.indexOf("-");
    const startStr = field.slice(0, dashIdx);
    const endStr   = field.slice(dashIdx + 1);
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range "${field}"`);
    }
    validateBounds(start, min, max, field);
    validateBounds(end, min, max, field);
    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end} in "${field}"`);
    }
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Single numeric value
  const num = parseInt(field, 10);
  if (isNaN(num) || String(num) !== field) {
    throw new SyntaxError(`Invalid cron field value "${field}"`);
  }
  validateBounds(num, min, max, field);
  return [num];
}

