        rangeMin = parseInt(startStr, 10);
        rangeMax = parseInt(endStr, 10);
      } else {
        rangeMin = parseInt(rangeExpr, 10);
      }
    }
    if (isNaN(rangeMin) || isNaN(rangeMax)) {
      throw new Error(`Invalid range in step expression: ${expression}`);
    }
    validateRange(rangeMin, rangeMax, min, max, expression);
    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  if (expression.includes("-")) {
    const [startStr, endStr] = expression.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: ${expression}`);
    }
    validateRange(start, end, min, max, expression);
    if (start > end) {
      throw new Error(`Range start ${start} is greater than end ${end}`);
    }
    return Array.from({ length: end - start + 1 }, (_, i) => i + start);
  }

  const value = parseInt(expression, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron field value: ${expression}`);
  }
  if (value < min || value > max) {
    throw new Error(`Value ${value} is out of range [${min}, ${max}]`);
