  // Wildcard
  if (segment === "*") {
    return expandRange(range.min, range.max, 1, range, segment);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const dashIdx = segment.indexOf("-");
    const start = parseInt(segment.slice(0, dashIdx), 10);
    const end   = parseInt(segment.slice(dashIdx + 1), 10);
    return expandRange(start, end, 1, range, segment);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new TypeError(`Invalid value "${segment}" — expected a number, range, step, or wildcard`);
  }
  assertInRange(value, range, segment);
  return [value];
}

function parseField(field: string, range: FieldRange): number[] {
  // Comma-separated list: parse each segment independently, then merge
  const segments = field.split(",");
  if (segments.length > 1) {
    const combined = segments.flatMap((seg) => {
      if (seg.trim() === "") {
        throw new TypeError(`Empty segment in comma list "${field}"`);
      }
      return parseSegment(seg.trim(), range);
    });
    // Deduplicate and sort
    return [...new Set(combined)].sort((a, b) => a - b);
  }

  return parseSegment(field.trim(), range);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 space-separated fields, got ${fields.length}`
    );
  }

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = fields;

  return {
    minute:     parseField(minuteStr,     FIELD_RANGES.minute),
    hour:       parseField(hourStr,       FIELD_RANGES.hour),
    dayOfMonth: parseField(dayOfMonthStr, FIELD_RANGES.dayOfMonth),
    month:      parseField(monthStr,      FIELD_RANGES.month),
    dayOfWeek:  parseField(dayOfWeekStr,  FIELD_RANGES.dayOfWeek),
  };
}
